// Flag any alias > 5% bounce rate
const critical = $input.all().map(i => i.json).filter(a => a.sends > 0 && (a.bounces / a.sends) > 0.05);
const warn = $input.all().map(i => i.json).filter(a => a.sends > 0 && (a.bounces / a.sends) > 0.03 && (a.bounces / a.sends) <= 0.05);
return [{json: {critical, warn, total_aliases: $input.all().length}}];
